//DBAS SQLite Wrapper
class DbasSqliteWrapper {
    version = 1;
    storeName = 'files';
    fsDBName = 'dbas_sqlite';
    basePath = '/data/';
    dbName = '';
    rawDbName = '';
    dbPath = '';
    rawDbPath = '';
    
    module = null;
    idbfs = null;
    intervalMs = 15000;

    async initialize(dbName = 'dbas.db') {
        this.module = await DbasSqlite();
        this.dbName = dbName.endsWith('.db') ? dbName : `${dbName}.db`;
        this.rawDbName = dbName.replace(/\.db$/, '');
        this.dbPath = dbName.endsWith('.db') ? `${this.basePath}${dbName}` : `${this.basePath}${dbName}.db`;
        this.rawDbPath = this.dbPath.replace(/\.db$/, '');

        try {
            if (!this.module.FS.lookupPath('/data').node) {
                this.module.FS.mkdir('/data');
            }
        } catch (e) {
            // Directory might already exist or lookupPath not available
            try {
                this.module.FS.mkdir('/data');
            } catch (e2) {
                // Directory likely already exists, continue
            }
        }

        // Setup direct IDBFS access
        if (typeof window !== 'undefined' && 'indexedDB' in window) {
            const idbfsResult = this.isIdbfsAvailable();
            
            if (idbfsResult.available) {
                // Store IDBFS reference for direct access
                this.idbfs = idbfsResult.idbfs;
            } else {
                console.warn('❌ IDBFS not available');
            }
        } else {
            console.warn('⚠️ IndexedDB not available in this environment');
        }

        if (navigator.storage && navigator.storage.persist) {
            const alreadyPersisted = await navigator.storage.persisted();
            if (!alreadyPersisted) {
                const isPersisted = await navigator.storage.persist();
                if (!isPersisted) {
                    console.warn('⚠️ Failed to request persistent storage.');
                }
            }
        }
    }

    // Check if file system is available and ready
    isFsAvailable() {
        // Simple check - just need module.FS to exist for direct IDBFS
        return !!this.module && this.module.FS;
    }

    // Check if IndexedDB file system is available
    isIdbfsAvailable() {
        if (!this.isFsAvailable()) {
            return { available: false, idbfs: null, location: null };
        }
        
        let idbfs = null;
        let location = '';
        const module = this.module;
        
        // First check the exported IDBFS (should be the primary location now)
        if (module.IDBFS) {
            idbfs = module.IDBFS;
            location = 'module.IDBFS';
        } else if (module.FS && module.FS.Nb && module.FS.Nb.IDBFS) {
            idbfs = module.FS.Nb.IDBFS;
            location = 'FS.Nb.IDBFS';
        } else if (module.FS && module.FS.filesystems && module.FS.filesystems.IDBFS) {
            idbfs = module.FS.filesystems.IDBFS;
            location = 'FS.filesystems.IDBFS';
        } else if (module.FS && module.FS.IDBFS) {
            idbfs = module.FS.IDBFS;
            location = 'FS.IDBFS';
        } else if (globalThis.IDBFS) {
            idbfs = globalThis.IDBFS;
            location = 'globalThis.IDBFS';
        }
        
        return {
            available: !!idbfs,
            idbfs: idbfs,
            location: location
        };
    }

    createStore(db) {
        if (db.objectStoreNames.contains(this.storeName)) {
            return true;
        }

        const store = db.createObjectStore(this.storeName, { keyPath: 'path' });
        store.createIndex('timestamp', 'timestamp', { unique: false });// For faster queries

        const result = db.objectStoreNames.contains(this.storeName);
        if (!result) {
            console.warn(`⚠️ Object store "${this.storeName}" not created in IndexedDB`);
        }

        return result;
    }

    checkIndexedDb() {
        return !!this.idbfs && typeof window !== 'undefined' && 'indexedDB' in window;
    }

    async restoreDB() {
        if (!this.checkIndexedDb()) {
            console.warn('⚠️ Direct IDBFS persistence not available to restore.');
            return;
        }

        return await new Promise((resolve, reject) => {
            try {
                const request = window.indexedDB.open(this.fsDBName, this.version);
                
                request.onerror = () => {
                    resolve(); // Not an error, just no data to restore
                };

                request.onupgradeneeded = (event) => {
                    this.createStore(event.target.result);
                };
                
                request.onsuccess = (event) => {
                    const db = event.target.result;
                    if (!db.objectStoreNames.contains(this.storeName)) {
                        resolve();
                        return;
                    }
                    
                    const transaction = db.transaction([this.storeName], 'readwrite');
                    const store = transaction.objectStore(this.storeName);
                    
                    const getRequest = store.get(this.dbPath);
                    getRequest.onsuccess = () => {
                        const result = getRequest.result;
                        if (result && result.data) {
                            try {
                                // Write data back to memory filesystem
                                this.module.FS.writeFile(this.dbPath, result.data);
                                
                                // Also try to restore auxiliary files
                                const baseName = this.dbPath.replace(/\.db$/, '');
                                const auxiliaryExtensions = ['-wal', '-shm', '-journal'];
                                
                                let auxRestored = 0;
                                auxiliaryExtensions.forEach(ext => {
                                    const auxPath = baseName + ext;
                                    const auxRequest = store.get(auxPath);
                                    
                                    auxRequest.onsuccess = () => {
                                        const auxResult = auxRequest.result;
                                        if (auxResult && auxResult.data) {
                                            try {
                                                this.module.FS.writeFile(auxPath, auxResult.data);
                                                auxRestored++;
                                            } catch (e) {
                                                console.warn(`⚠️ Error restoring auxiliary file ${auxPath}:`, e.message);
                                            }
                                        }
                                    };
                                });

                                resolve();
                            } catch (e) {
                                console.warn('❌ Error writing restored data:', e.message);
                                reject(e);
                            }
                        } else {
                            console.warn(`⚠️ No data found for ${this.dbPath}.`, getRequest);
                            resolve();
                        }
                    };
                    
                    getRequest.onerror = () => {
                        console.warn('❌ Error reading from IndexedDB');
                        reject(new Error('IndexedDB read failed'));
                    };
                };
            } catch (e) {
                console.warn('❌ Error in restore operation:', e);
                reject(e);
            }
        });
    }

    async persistDB() {
        if (!this.checkIndexedDb()) {
            console.warn('⚠️ Direct IDBFS persistence not available to persist.');
            return;
        }

        return await new Promise((resolve, reject) => {
            try {
                // Use IndexedDB directly to store database files
                const request = indexedDB.open(this.fsDBName, this.version);
                let dbUpgraded = false;
                
                request.onerror = () => {
                    console.warn('❌ Failed to open IndexedDB for persistence');
                    reject(new Error('IndexedDB open failed'));
                };
                
                request.onupgradeneeded = (event) => {
                    const db = event.target.result;
                    createDbasStore(db);
                    dbUpgraded = true;
                };
                
                request.onsuccess = (event) => {
                    // If database was upgraded, wait a moment for transaction to complete
                    if (dbUpgraded) {
                        setTimeout(() => this.proceedWithPersistence(event.target.result), 50);
                    } else {
                        this.proceedWithPersistence(event.target.result);
                    }
                    resolve();
                };
            } catch (e) {
                console.warn('❌ Error in optimized direct IDBFS persistence:', e);
                reject(e);
            }
        });
    }

    proceedWithPersistence (db) {
        // Ensure the object store exists before proceeding
        if (!db.objectStoreNames.contains(this.storeName)) {
            const message = `❌ Object store "${this.storeName}" not found`;
            console.warn(message);
            throw new Error(message);
        }
        
        const transaction = db.transaction([this.storeName], 'readwrite');
        const store = transaction.objectStore(this.storeName);
        const filesToPersist = [];
        
        try {
            const data = this.module.FS.readFile(this.dbPath);
            if (data && data.length > 0) {
                filesToPersist.push({
                path: this.dbPath,
                data: data,
                timestamp: Date.now(),
                size: data.length,
                type: 'database'
                });
            }
        } catch (e) {
            console.log('⚠️ Failed to read database file: ', e);
            console.log(this.module.FS.readdir('/data'));
            // Database file may not exist yet
        }
        
        // Also check for SQLite auxiliary files (WAL, SHM, etc.)
        const auxiliaryExtensions = ['-wal', '-shm', '-journal'];
        auxiliaryExtensions.forEach(ext => {
            const auxPath = this.rawDbPath + ext;
            try {
                const data = this.module.FS.readFile(auxPath);
                if (data && data.length > 0) {
                filesToPersist.push({
                    path: auxPath,
                    data: data,
                    timestamp: Date.now(),
                    size: data.length,
                    type: 'auxiliary'
                });
                }
            } catch (e) {
                // Auxiliary files may not exist, this is normal
            }
        });
        
        if (filesToPersist.length === 0) {
            console.warn(`⚠️ No files to persist for ${this.dbName}`);
            return;
        }
        
        // 🚀 PERFORMANCE: Use batch operations
        let completed = 0;
        const total = filesToPersist.length;
        filesToPersist.forEach(fileEntry => {
            const putRequest = store.put(fileEntry);
            putRequest.onsuccess = () => {
                completed++;
                if (completed === total) {
                    return;
                }
            };
            
            putRequest.onerror = () => {
                console.warn(`❌ Failed to store ${fileEntry.path}`);
                completed++;
                if (completed === total) {
                    return;
                }
            };
        });
        
        // 📊 PERFORMANCE: Add cleanup for old files (keep last 10 versions)
        const cleanupTransaction = db.transaction([this.storeName], 'readwrite');
        const cleanupStore = cleanupTransaction.objectStore(this.storeName);
        const timestampIndex = cleanupStore.index('timestamp');
        
        const cleanupRequest = timestampIndex.openCursor(null, 'prev');
        let fileCount = 0;
        
        cleanupRequest.onsuccess = (event) => {
            const cursor = event.target.result;
            if (cursor) {
                fileCount++;
                if (fileCount > 10) { // Keep only last 10 versions
                    cursor.delete();
                }
                cursor.continue();
            }
        };
    }

    fileExists(path) {
        try {
            this.module.FS.stat(path);
            return true;
        } catch (e) {
            return false;
        }
    }

    async databaseExists() {
        const dbs = await globalThis.indexedDB.databases();
        return this.fileExists(this.dbPath) && dbs.some(db => db.name === this.fsDBName);
    }

    async attachDb(content) {
        this.module.FS.writeFile(this.dbPath, content);
        await this.persistDB();
    }

    async dropDb() {
        try {
            if (this.DbasSqliteWrapper.fileExists(this.dbPath)) this.module.FS.unlink(this.dbPath);
            ['-wal','-shm','-journal'].forEach(ext => {
                const p = this.rawDbPath + ext;
                try { if (this.DbasSqliteWrapper.fileExists(p)) this.module.FS.unlink(p); } catch (_) {}
            });
        } catch (e) {
            console.error("❌ Error unlinking database files: " + e.message);
        }

        if (this.isFsAvailable() && this.module.FS.syncfs) {
            await new Promise((resolve, reject) => {
                this.module.FS.syncfs(false, (err) => err ? reject(err) : resolve());
            });
        }

        if (this.DbasSqliteWrapper.checkIndexedDb()) {
            const req = indexedDB.open(this.fsDBName, this.version);
            req.onsuccess = (ev) => {
                const db = ev.target.result;
                if (db.objectStoreNames.contains(this.storeName)) {
                    const tx = db.transaction([this.storeName], 'readwrite');
                    const store = tx.objectStore(this.storeName);
                    store.delete(this.dbPath);
                    ['-wal','-shm','-journal'].forEach(ext => store.delete(this.rawDbPath + ext));
                }
                try { db.close(); } catch (e) {
                    console.error("❌ Error closing database: " + e.message);
                }
            };
        }

        try {
            if (this.module && this.module.FS && this.module.FS.unmount) {
                this.module.FS.unmount('/data');
            }
        } catch (e) {
            console.error("❌ Error unmounting filesystem: " + e.message);
        }
    }

    allocString(str) {
        const len = this.module.lengthBytesUTF8(str) + 1;
        const ptr = this.module._malloc(len);
        this.module.stringToUTF8(str, ptr, len);
        return ptr;
    }


    async openDb() {
        const dbPathPtr = this.allocString(this.dbPath);
        const dbPtr = this.module._OpenDb(dbPathPtr);
        if (!dbPtr) {
            throw new Error(`Failed to open database with invalid pointer: ${this.dbPath}`);
        }
        await this.persistDB();
        this.module._free(dbPathPtr);
        return dbPtr;
    }

    isOpened(dbPtr) {
        return this.module._IsOpened(dbPtr);
    }

    executeSql(dbPtr, sql) {
        const sqlPtr = this.allocString(sql);
        try {
            return this.module._ExecuteSql(dbPtr, sqlPtr);
        } finally {
            this.module._free(sqlPtr);
        }
    }

    prepareQuery(dbPtr, sql) {
        const sqlPtr = this.allocString(sql);
        try {
            return this.module._PrepareQuery(dbPtr, sqlPtr);
        } finally {
            this.module._free(sqlPtr);
        }
    }

    bindText(dbPtr, index, value) {
        const textPtr = this.allocString(value);
        try {
            this.module._BindText(dbPtr, index, textPtr);
        } finally {
            this.module._free(textPtr);
        }
    }

    bindInt(dbPtr, index, value) {
        this.module._BindInt(dbPtr, index, value);
    }

    bindFloat(dbPtr, index, value) {
        this.module._BindFloat(dbPtr, index, value);
    }
    
    bindDouble(dbPtr, index, value) {
        this.module._BindDouble(dbPtr, index, value);
    }
    
    bindNull(dbPtr, index) {
        this.module._BindNull(dbPtr, index);
    }
    
    bindBlob(dbPtr, index, data) {
        const len = data?.length ?? 0;
        const dataPtr = this.module._malloc(len);
        try {
            this.module.HEAPU8.set(data, dataPtr);
            this.module._BindBlob(dbPtr, index, dataPtr, len);
        } finally {
            this.module._free(dataPtr);
        }
    }

    bindNameText(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        const valuePtr = this.allocString(value);
        try {
            this.module._BindNameText(dbPtr, namePtr, valuePtr);
        } finally {
            this.module._free(namePtr);
            this.module._free(valuePtr);
        }
    }
    
    bindNameInt(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameInt(dbPtr, namePtr, value);
        } finally {
            this.module._free(namePtr);
        }
    }
    
    bindNameFloat(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameFloat(dbPtr, namePtr, value);
        } finally {
            this.module._free(namePtr);
        }
    }
    
    bindNameDouble(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameDouble(dbPtr, namePtr, value);
        } finally {
            this.module._free(namePtr);
        }
    }
    
    bindNameNull(dbPtr, name) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameNull(dbPtr, namePtr);
        } finally {
            this.module._free(namePtr);
        }
    }
    
    bindNameBlob(dbPtr, name, data) {
        const len = data?.length ?? 0;
        const namePtr = this.allocString(name);
        const dataPtr = this.module._malloc(len);
        try {
            this.module.HEAPU8.set(data, dataPtr);
            this.module._BindNameBlob(dbPtr, namePtr, dataPtr, len);
        } finally {
            this.module._free(namePtr);
            this.module._free(dataPtr);
        }
    }

    readRow(dbPtr) {
        return this.module._ReadRow(dbPtr);
    }
    
    isNull(dbPtr, index) {
        return this.module._IsNull(dbPtr, index);
    }
    
    getColumnText(dbPtr, index) {
        const textPtr = this.module._GetColumnText(dbPtr, index);
        const text = textPtr ? this.module.UTF8ToString(textPtr) : null;
        this.module._free(textPtr);
        return text;
    }
    
    getColumnInt(dbPtr, index) {
        return this.module._GetColumnInt(dbPtr, index);
    }
    
    getColumnFloat(dbPtr, index) {
        return this.module._GetColumnFloat(dbPtr, index);
    }
    
    getColumnDouble(dbPtr, index) {
        return this.module._GetColumnDouble(dbPtr, index);
    }
    
    getColumnType(dbPtr, index) {
        return this.module._GetColumnType(dbPtr, index);
    }
    
    getColumnBlob(dbPtr, index) {
        const blobPtr = this.module._GetColumnBlob(dbPtr, index);
        const length = this.module._GetColumnBytes(dbPtr, index);
        const blob = blobPtr ? new Uint8Array(this.module.HEAPU8.buffer, blobPtr, length) : null;
        this.module._free(blobPtr);
        return blob;
    }
    
    getColumnBytes(dbPtr, index) {
        return this.module._GetColumnBytes(dbPtr, index);
    }
    
    getColumnName(dbPtr, index) {
        const namePtr = this.module._GetColumnName(dbPtr, index);
        const name = namePtr ? this.module.UTF8ToString(namePtr) : null;
        this.module._free(namePtr);
        return name;
    }
    
    getColumnCount(dbPtr) {
        return this.module._GetColumnCount(dbPtr);
    }

    getLastDbError(dbPtr) {
        const errorPtr = this.module._GetLastDbError(dbPtr);
        const lastErrorStr = errorPtr ? this.module.UTF8ToString(errorPtr) : `Unknown error: ${errorPtr}`;
        this.module._free(errorPtr);
        return lastErrorStr;
    }
    
    getAffectedRows(dbPtr) {
        return this.module._GetAffectedRows(dbPtr);
    }
    
    getLastInsertedId(dbPtr) {
        return this.module._GetLastInsertedId(dbPtr);
    }
    

    closeReader(dbPtr) {
        this.module._CloseReader(dbPtr);
    }
    
    async closeDb(dbPtr) {
        this.module._CloseDb(dbPtr);
        await this.persistDB();
    }
}
//End of DBAS SQLite Wrapper

// Export for global access (better for Dart JS interop)
if (typeof DbasSqlite !== 'undefined') {
  globalThis.DbasSqlite = DbasSqlite;
} else {
  console.error('❌ DbasSqlite is not defined');
}

if (typeof DbasSqliteWrapper !== 'undefined') {
  globalThis.DbasSqliteWrapper = new DbasSqliteWrapper();
} else {
  console.error('❌ DbasSqliteWrapper is not defined');
}

globalThis.initPersistentFS = async function(dbName = 'dbas.db') {
  const module = globalThis.DbasSqliteWrapper;
  await module.initialize(dbName);

  await module.restoreDB();
  globalThis.startAutoPersist();

  return module;
}

// Start automatic periodic persistence
let autoInterval;
globalThis.startAutoPersist = function() {
  globalThis.stopAutoPersist(); // Clear any existing interval
    
  if (globalThis.DbasSqliteWrapper.checkIndexedDb()) {
    autoInterval = setInterval(async () => {
      try {
        await globalThis.DbasSqliteWrapper.persistDB();
      } catch (error) {
        console.warn('⚠️ Auto-persist failed:', error.message);
      }
    }, globalThis.DbasSqliteWrapper.intervalMs);
  }
};

globalThis.stopAutoPersist = function() {
  if (autoInterval) {
    clearInterval(autoInterval);
    autoInterval = null;
  }
};

globalThis.dropDb = globalThis.DbasSqliteWrapper.dropDb;

// Auto-persist on page unload (if in browser environment)
if (typeof globalThis.window !== 'undefined') {
  globalThis.window.addEventListener('beforeunload', async () => {
    // Stop auto-persist and do final save
    stopAutoPersist();
    await globalThis.DbasSqliteWrapper.persistDB();
  });
  
  // Also persist on visibility change (when user switches tabs)
  globalThis.window.addEventListener('visibilitychange', async () => {
    if (globalThis.window.document.visibilityState === 'hidden') {
      await globalThis.DbasSqliteWrapper.persistDB();
    }
  });
  
  // Stop auto-persist when page is being unloaded
  globalThis.window.addEventListener('unload', () => {
    stopAutoPersist();
  });
}

globalThis.isFsAvailable = globalThis.DbasSqliteWrapper.isFsAvailable;
globalThis.isIdbfsAvailable = globalThis.DbasSqliteWrapper.isIdbfsAvailable;
